example.code:
const CardContext = createContext<{ variant: 'default' | 'elevated' } | null>(null);

function useCardContext() {
  const ctx = useContext(CardContext);
  if (!ctx) throw new Error('Card sub-components must be used inside <Card>');
  return ctx;
}

function CardRoot({ children, variant = 'default', className }: CardProps) {
  return (
    <CardContext.Provider value={{ variant }}>
      <article className={clsx(styles.card, styles[variant], className)}>
        {children}
      </article>
    </CardContext.Provider>
  );
}

export function CardHeader({ children, className }: SubProps) {
  return <header className={clsx(styles.header, className)}>{children}</header>;
}

// Both forms: named export + Object.assign for ergonomic JSX
export const Card = Object.assign(CardRoot, { Header: CardHeader, Content: CardContent });
